Explain why this state machine optimization constraint fails to achieve One-Hot encoding.
(* fsm_encoding = "one_hot" *) reg [1:0] state;
parameter IDLE=0, WAIT=1, GO=2, DONE=3;
always @(posedge clk) begin
  state <= state + 1'b1;
end

